// Store locator for 300 coffee shop locations
mapboxgl.accessToken = TOKEN;
const map = new mapboxgl.Map({ container: 'map', style: 'mapbox://styles/mapbox/streets-v12' });

// Display markers
function loadMarkers(storeData) {
  storeData.features.forEach(store => {
    new mapboxgl.Marker()
      .setLngLat(store.geometry.coordinates)
      .addTo(map);
  });
}

// Filter: fetch filtered results from server on each keystroke
async function filterStores(searchTerm) {
  const results = await fetch(`/api/stores?q=${encodeURIComponent(searchTerm)}`).then(r => r.json());

  // Remove old layer and re-add with filtered data
  if (map.getLayer('stores-layer')) map.removeLayer('stores-layer');
  if (map.getSource('stores')) map.removeSource('stores');
  map.addSource('stores', { type: 'geojson', data: results });
  map.addLayer({ id: 'stores-layer', type: 'symbol', source: 'stores', layout: { 'icon-image': 'marker-15' } });

  document.getElementById('listings').innerHTML = '';
  buildLocationList(results);
}

// Highlight selected listing
function highlightListing(id) {
  document.querySelectorAll('.listing').forEach(l => l.classList.remove('active'));
  const listing = document.getElementById(`listing-${id}`);
  listing.classList.add('active');
}

